    public Object calculateRateLimiterCost(Object api, Object method, Object path, Object parameters, Object... optionalArgs)
    {
        Object config = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
        Object step = this.safeInteger(config, "step");
        Object cost = this.safeInteger(config, "cost", 1);
        Object orders = this.safeList2(parameters, "orderList", "orderDataList", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
        Object ordersLength = Helpers.getArrayLength(orders);
        if (Helpers.isTrue(Helpers.isTrue((!Helpers.isEqual(step, null))) && Helpers.isTrue((Helpers.isGreaterThan(ordersLength, step)))))
        {
            Object numberOfSteps = Math.ceil(Double.parseDouble(Helpers.toString(Helpers.divide(ordersLength, step))));
            return Helpers.multiply(cost, numberOfSteps);
        } else
        {
            return cost;
        }
    }

