    /**
     * @method
     * @name coincatch#fetchCurrencies
     * @description fetches all available currencies on an exchange
     * @see https://coincatch.github.io/github.io/en/spot/#get-coin-list
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} an associative dictionary of currencies
     */
    public java.util.concurrent.CompletableFuture<Object> fetchCurrencies(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            Object response = (this.publicGetApiSpotV1PublicCurrencies(parameters)).join();
            Object data = this.safeList(response, "data", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            //
            //     {
            //         "code": "00000",
            //         "msg": "success",
            //         "requestTime": 1725102364202,
            //         "data": [
            //             {
            //                 "coinId": "1",
            //                 "coinName": "BTC",
            //                 "transfer": "true",
            //                 "chains": [
            //                     {
            //                         "chainId": "10",
            //                         "chain": "BITCOIN",
            //                         "needTag": "false",
            //                         "withdrawable": "true",
            //                         "rechargeable": "true",
            //                         "withdrawFee": "0.0005",
            //                         "extraWithDrawFee": "0",
            //                         "depositConfirm": "1",
            //                         "withdrawConfirm": "1",
            //                         "minDepositAmount": "0.00001",
            //                         "minWithdrawAmount": "0.001",
            //                         "browserUrl": "https://blockchair.com/bitcoin/transaction/"
            //                     }
            //                 ]
            //             },
            //             ...
            //         ]
            //     }
            //
            Object result = new java.util.HashMap<String, Object>() {{}};
            Object currenciesIds = new java.util.ArrayList<Object>(java.util.Arrays.asList());
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(data)); i++)
            {
                Object currecy = Helpers.GetValue(data, i);
                Object currencyId = this.safeString(currecy, "coinName");
                ((java.util.List<Object>)currenciesIds).add(currencyId);
                Object code = this.safeCurrencyCode(currencyId);
                Object networks = this.safeList(currecy, "chains");
                Object parsedNetworks = new java.util.HashMap<String, Object>() {{}};
                for (var j = 0; Helpers.isLessThan(j, Helpers.getArrayLength(networks)); j++)
                {
                    Object network = Helpers.GetValue(networks, j);
                    Object networkId = this.safeString(network, "chain");
                    Object networkCode = this.networkIdToCode(networkId);
                    Helpers.addElementToObject(parsedNetworks, networkCode, new java.util.HashMap<String, Object>() {{
        put( "id", networkId );
        put( "network", networkCode );
        put( "limits", new java.util.HashMap<String, Object>() {{
            put( "deposit", new java.util.HashMap<String, Object>() {{
                put( "min", Coincatch.this.safeNumber(network, "minDepositAmount") );
                put( "max", null );
            }} );
            put( "withdraw", new java.util.HashMap<String, Object>() {{
                put( "min", Coincatch.this.safeNumber(network, "minWithdrawAmount") );
                put( "max", null );
            }} );
        }} );
        put( "active", null );
        put( "deposit", Helpers.isEqual(Coincatch.this.safeString(network, "rechargeable"), "true") );
        put( "withdraw", Helpers.isEqual(Coincatch.this.safeString(network, "withdrawable"), "true") );
        put( "fee", Coincatch.this.safeNumber(network, "withdrawFee") );
        put( "precision", null );
        put( "info", network );
    }});
                }
                
                Helpers.addElementToObject(result, code, this.safeCurrencyStructure(new java.util.HashMap<String, Object>() {{
        put( "id", currencyId );
        put( "numericId", Coincatch.this.safeInteger(currecy, "coinId") );
        put( "code", code );
        put( "precision", null );
        put( "type", null );
        put( "name", null );
        put( "active", null );
        put( "deposit", null );
        put( "withdraw", null );
        put( "fee", null );
        put( "limits", new java.util.HashMap<String, Object>() {{
            put( "deposit", new java.util.HashMap<String, Object>() {{
                put( "min", null );
                put( "max", null );
            }} );
            put( "withdraw", new java.util.HashMap<String, Object>() {{
                put( "min", null );
                put( "max", null );
            }} );
        }} );
        put( "networks", parsedNetworks );
        put( "info", currecy );
    }}));
            }
            if (Helpers.isTrue(Helpers.isEqual(this.safeList(this.options, "currencyIdsListForParseMarket"), null)))
            {
                Helpers.addElementToObject(this.options, "currencyIdsListForParseMarket", currenciesIds);
            }
            return result;
        }, io.github.ccxt.Exchange.VIRTUAL_EXECUTOR);

    }

