    public Object parseDepositWithdrawFee(Object fee, Object... optionalArgs)
    {
        //
        // {
        //     "coinId":"1",
        //     "coinName":"BTC",
        //     "transfer":"true",
        //     "chains":[
        //         {
        //             "chain":null,
        //             "needTag":"false",
        //             "withdrawable":"true",
        //             "rechargeAble":"true",
        //             "withdrawFee":"0.005",
        //             "depositConfirm":"1",
        //             "withdrawConfirm":"1",
        //             "minDepositAmount":"0.001",
        //             "minWithdrawAmount":"0.001",
        //             "browserUrl":"https://blockchair.com/bitcoin/testnet/transaction/"
        //         }
        //     ]
        // }
        //
        Object currency = Helpers.getArg(optionalArgs, 0, null);
        Object chains = this.safeList(fee, "chains", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
        Object chainsLength = Helpers.getArrayLength(chains);
        Object result = new java.util.HashMap<String, Object>() {{
            put( "info", fee );
            put( "withdraw", new java.util.HashMap<String, Object>() {{
                put( "fee", null );
                put( "percentage", null );
            }} );
            put( "deposit", new java.util.HashMap<String, Object>() {{
                put( "fee", null );
                put( "percentage", null );
            }} );
            put( "networks", new java.util.HashMap<String, Object>() {{}} );
        }};
        for (var i = 0; Helpers.isLessThan(i, chainsLength); i++)
        {
            Object chain = Helpers.GetValue(chains, i);
            Object networkId = this.safeString(chain, "chain");
            Object currencyCode = this.safeString(currency, "code");
            Object networkCode = this.networkIdToCode(networkId, currencyCode);
            Helpers.addElementToObject(Helpers.GetValue(result, "networks"), networkCode, new java.util.HashMap<String, Object>() {{
    put( "deposit", new java.util.HashMap<String, Object>() {{
        put( "fee", null );
        put( "percentage", null );
    }} );
    put( "withdraw", new java.util.HashMap<String, Object>() {{
        put( "fee", Coincatch.this.safeNumber(chain, "withdrawFee") );
        put( "percentage", false );
    }} );
}});
            if (Helpers.isTrue(Helpers.isEqual(chainsLength, 1)))
            {
                Helpers.addElementToObject(Helpers.GetValue(result, "withdraw"), "fee", this.safeNumber(chain, "withdrawFee"));
                Helpers.addElementToObject(Helpers.GetValue(result, "withdraw"), "percentage", false);
            }
        }
        return result;
    }

