            //                 "volumePlace": "3",
            //                 "pricePlace": "1",
            //                 "sizeMultiplier": "0.001",
            //                 "symbolType": "perpetual",
            //                 "symbolStatus": "normal",
            //                 "offTime": "-1",
            //                 "limitOpenTime": "-1",
            //                 "maintainTime": "",
            //                 "symbolName": "BTCUSDT",
            //                 "minTradeUSDT": null,
            //                 "maxPositionNum": null,
            //                 "maxOrderNum": null
            //             }
            //         ]
            //     }
            //
            Object swapUMCBL = this.safeList(response, "data", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            Helpers.addElementToObject(request, "productType", "dmcbl");
            response = (this.publicGetApiMixV1MarketContracts(this.extend(request, parameters))).join();
            //
            //     {
            //         "code":"00000",
            //         "msg":"success",
