            //                 "volumePlace":"3",
            //                 "pricePlace":"1",
            //                 "sizeMultiplier":"0.001",
            //                 "symbolType":"perpetual",
            //                 "symbolStatus":"normal",
            //                 "offTime":"-1",
            //                 "limitOpenTime":"-1",
            //                 "maintainTime":"",
            //                 "symbolName":"BTCUSD",
            //                 "minTradeUSDT":null,
            //                 "maxPositionNum":null,
            //                 "maxOrderNum":null
