    public Object parseTicker(Object ticker, Object... optionalArgs)
    {
        //
        // spot
        //     {
        //         "symbol": "BTCUSDT",
        //         "high24h": "59461.34",
        //         "low24h": "57723.23",
        //         "close": "59056.02",
        //         "quoteVol": "18240112.23368",
        //         "baseVol": "309.05564",
        //         "usdtVol": "18240112.2336744",
        //         "ts": "1725114038951",
        //         "buyOne": "59055.85",
        //         "sellOne": "59057.45",
        //         "bidSz": "0.0139",
        //         "askSz": "0.0139",
        //         "openUtc0": "59126.71",
        //         "changeUtc": "-0.0012",
        //         "change": "0.01662"
        //     }
        //
        // swap
        //     {
        //         "symbol": "ETHUSDT_UMCBL",
        //         "last": "2540.6",
        //         "bestAsk": "2540.71",
        //         "bestBid": "2540.38",
        //         "bidSz": "12.1",
        //         "askSz": "20",
        //         "high24h": "2563.91",
        //         "low24h": "2398.3",
        //         "timestamp": "1725316687177",
        //         "priceChangePercent": "0.01134",
        //         "baseVolume": "706928.96",
        //         "quoteVolume": "1756401737.8766",
        //         "usdtVolume": "1756401737.8766",
        //         "openUtc": "2424.49",
        //         "chgUtc": "0.04789",
        //         "indexPrice": "2541.977142",
        //         "fundingRate": "0.00006",
        //         "holdingAmount": "144688.49",
        //         "deliveryStartTime": null,
        //         "deliveryTime": null,
        //         "deliveryStatus": "normal"
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object timestamp = this.safeInteger2(ticker, "ts", "timestamp");
        Object marketId = this.safeString(ticker, "symbol", "");
        if (Helpers.isTrue(Helpers.isLessThan(Helpers.getIndexOf(marketId, "_"), 0)))
        {
            marketId = Helpers.add(marketId, "_SPBL"); // spot markets from tickers endpoints have no suffix specific for market id
        }
        market = this.safeMarketCustom(marketId, market);
        Object last = this.safeString2(ticker, "close", "last");
        final Object finalMarket = market;
        return this.safeTicker(new java.util.HashMap<String, Object>() {{
            put( "symbol", Helpers.GetValue(finalMarket, "symbol") );
            put( "timestamp", timestamp );
            put( "datetime", Coincatch.this.iso8601(timestamp) );
            put( "high", Coincatch.this.safeString(ticker, "high24h") );
            put( "low", Coincatch.this.safeString(ticker, "low24h") );
            put( "bid", Coincatch.this.safeString2(ticker, "buyOne", "bestBid") );
            put( "bidVolume", Coincatch.this.safeString(ticker, "bidSz") );
            put( "ask", Coincatch.this.safeString2(ticker, "sellOne", "bestAsk") );
            put( "askVolume", Coincatch.this.safeString(ticker, "askSz") );
            put( "vwap", null );
            put( "open", Coincatch.this.safeString2(ticker, "openUtc0", "openUtc") );
            put( "close", last );
            put( "last", last );
            put( "previousClose", null );
            put( "change", null );
            put( "percentage", Precise.stringMul(Coincatch.this.safeString2(ticker, "changeUtc", "chgUtc"), "100") );
            put( "average", null );
            put( "baseVolume", Coincatch.this.safeString2(ticker, "baseVol", "baseVolume") );
            put( "quoteVolume", Coincatch.this.safeString2(ticker, "quoteVol", "quoteVolume") );
            put( "indexPrice", Coincatch.this.safeString(ticker, "indexPrice") );
            put( "markPrice", null );
            put( "info", ticker );
        }}, market);
    }

