    /**
     * @method
     * @name coincatch#fetchOHLCV
     * @see https://coincatch.github.io/github.io/en/spot/#get-candle-data
     * @see https://coincatch.github.io/github.io/en/mix/#get-candle-data
     * @description fetches historical candlestick data containing the open, high, low, and close price, and the volume of a market
     * @param {string} symbol unified symbol of the market to fetch OHLCV data for
     * @param {string} timeframe the length of time each candle represents
     * @param {int} [since] timestamp in ms of the earliest candle to fetch
     * @param {int} [limit] the maximum amount of candles to fetch (default 100)
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @param {int} [params.until] timestamp in ms of the latest candle to fetch
     * @param {string} [params.price] "mark" for mark price candles
     * @returns {int[][]} A list of candles ordered as timestamp, open, high, low, close, volume
     */
    public java.util.concurrent.CompletableFuture<Object> fetchOHLCV(Object symbol, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object timeframe = Helpers.getArg(optionalArgs, 0, "1m");
            Object since = Helpers.getArg(optionalArgs, 1, null);
            Object limit = Helpers.getArg(optionalArgs, 2, null);
            Object parameters = Helpers.getArg(optionalArgs, 3, new java.util.HashMap<String, Object>() {{}});
            Object methodName = "fetchOHLCV";
            (this.loadMarkets()).join();
            Object market = this.market(symbol);
            Object request = new java.util.HashMap<String, Object>() {{
                put( "symbol", Helpers.GetValue(market, "id") );
            }};
            Object until = null;
            var untilparametersVariable = this.handleOptionAndParams(parameters, methodName, "until");
            until = ((java.util.List<Object>) untilparametersVariable).get(0);
            parameters = ((java.util.List<Object>) untilparametersVariable).get(1);
            Object marketType = Helpers.GetValue(market, "type");
            Object timeframes = Helpers.GetValue(Helpers.GetValue(this.options, "timeframes"), marketType);
            Object encodedTimeframe = this.safeString(timeframes, timeframe, timeframe);
            Object maxLimit = 1000;
            Object requestedLimit = limit;
            if (Helpers.isTrue(Helpers.isTrue((!Helpers.isEqual(since, null))) || Helpers.isTrue((!Helpers.isEqual(until, null)))))
            {
                requestedLimit = maxLimit; // the exchange returns only last limit candles, so we have to fetch max limit if since or until are provided
            }
            if (Helpers.isTrue(!Helpers.isEqual(requestedLimit, null)))
            {
                Helpers.addElementToObject(request, "limit", requestedLimit);
            }
            Object response = null;
            if (Helpers.isTrue(Helpers.GetValue(market, "spot")))
            {
                Helpers.addElementToObject(request, "period", encodedTimeframe);
                if (Helpers.isTrue(!Helpers.isEqual(since, null)))
                {
                    Helpers.addElementToObject(request, "after", since);
                }
                if (Helpers.isTrue(!Helpers.isEqual(until, null)))
                {
                    Helpers.addElementToObject(request, "before", until);
                }
                response = (this.publicGetApiSpotV1MarketCandles(this.extend(request, parameters))).join();
                //
                //     {
                //         "code": "00000",
                //         "msg": "success",
                //         "requestTime": 1725142465742,
                //         "data": [
                //             {
                //                 "open": "2518.6",
                //                 "high": "2519.19",
                //                 "low": "2518.42",
                //                 "close": "2518.86",
                //                 "quoteVol": "17193.239401",
                //                 "baseVol": "6.8259",
                //                 "usdtVol": "17193.239401",
                //                 "ts": "1725142200000"
                //             },
                //             ...
                //         ]
                //     }
                //
                Object data = this.safeList(response, "data", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
                return this.parseOHLCVs(data, market, timeframe, since, limit);
            } else if (Helpers.isTrue(Helpers.GetValue(market, "swap")))
            {
                Helpers.addElementToObject(request, "granularity", encodedTimeframe);
                if (Helpers.isTrue(Helpers.isEqual(until, null)))
                {
                    until = this.milliseconds();
                }
                if (Helpers.isTrue(Helpers.isEqual(since, null)))
                {
                    Object duration = this.parseTimeframe(timeframe);
                    since = Helpers.subtract(until, (Helpers.multiply(Helpers.multiply(duration, maxLimit), 1000)));
                }
                Helpers.addElementToObject(request, "startTime", since); // since and until are mandatory for swap
                Helpers.addElementToObject(request, "endTime", until);
                Object priceType = null;
                var priceTypeparametersVariable = this.handleOptionAndParams(parameters, methodName, "price");
                priceType = ((java.util.List<Object>) priceTypeparametersVariable).get(0);
                parameters = ((java.util.List<Object>) priceTypeparametersVariable).get(1);
                if (Helpers.isTrue(Helpers.isEqual(priceType, "mark")))
                {
                    Helpers.addElementToObject(request, "kLineType", "market mark index");
                }
                response = (this.publicGetApiMixV1MarketCandles(this.extend(request, parameters))).join();
                //
                //     [
                //         [
                //             "1725379020000",
                //             "57614",
                //             "57636",
                //             "57614",
                //             "57633",
                //             "28.725",
                //             "1655346.493"
                //         ],
                //         ...
                //     ]
                //
                return this.parseOHLCVs(response, market, timeframe, since, limit);
            } else
            {
                throw new NotSupported((String)Helpers.add(Helpers.add(Helpers.add(Helpers.add(Helpers.add(this.id, " "), methodName), "() is not supported for "), Helpers.GetValue(market, "type")), " type of markets")) ;
            }
        }, io.github.ccxt.Exchange.VIRTUAL_EXECUTOR);

    }

