    /**
     * @method
     * @name coincatch#fetchFundingRateHistory
     * @description fetches historical funding rate prices
     * @see https://coincatch.github.io/github.io/en/mix/#get-history-funding-rate
     * @param {string} symbol unified symbol of the market to fetch the funding rate history for
     * @param {int} [since] timestamp in ms of the earliest funding rate to fetch
     * @param {int} [limit] the maximum amount of entries to fetch
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @param {int} [params.pageNo] the page number to fetch
     * @param {bool} [params.nextPage] whether to query the next page (default false)
     * @returns {object[]} a list of [funding rate structures]{@link https://docs.ccxt.com/?id=funding-rate-history-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> fetchFundingRateHistory(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object symbol = Helpers.getArg(optionalArgs, 0, null);
            Object since = Helpers.getArg(optionalArgs, 1, null);
            Object limit = Helpers.getArg(optionalArgs, 2, null);
            Object parameters = Helpers.getArg(optionalArgs, 3, new java.util.HashMap<String, Object>() {{}});
            if (Helpers.isTrue(Helpers.isEqual(symbol, null)))
            {
                throw new ArgumentsRequired((String)Helpers.add(this.id, " fetchFundingRateHistory() requires a symbol argument")) ;
            }
            (this.loadMarkets()).join();
            Object maxEntriesPerRequest = 100;
            Object market = this.market(symbol);
            Object request = new java.util.HashMap<String, Object>() {{
                put( "symbol", Helpers.GetValue(market, "id") );
            }};
            Object requestedLimit = limit;
            if (Helpers.isTrue(!Helpers.isEqual(since, null)))
            {
                requestedLimit = maxEntriesPerRequest;
            }
            if (Helpers.isTrue(!Helpers.isEqual(requestedLimit, null)))
            {
                Helpers.addElementToObject(request, "pageSize", requestedLimit);
            }
            Object response = (this.publicGetApiMixV1MarketHistoryFundRate(this.extend(request, parameters))).join();
            //
            //     {
            //         "code": "00000",
            //         "msg": "success",
            //         "requestTime": 1725455810888,
            //         "data": [
            //             {
            //                 "symbol": "BTCUSD",
            //                 "fundingRate": "0.000635",
            //                 "settleTime": "1724889600000"
            //             }
            //         ]
            //     }
            //
            Object data = this.safeList(response, "data", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            Object rates = new java.util.ArrayList<Object>(java.util.Arrays.asList());
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(data)); i++)
            {
                Object entry = Helpers.GetValue(data, i);
                Object timestamp = this.safeInteger(entry, "settleTime");
                ((java.util.List<Object>)rates).add(new java.util.HashMap<String, Object>() {{
                    put( "info", entry );
                    put( "symbol", Coincatch.this.safeSymbol(Coincatch.this.safeString(entry, "symbol"), market, null, "swap") );
                    put( "fundingRate", Coincatch.this.safeNumber(entry, "fundingRate") );
                    put( "timestamp", timestamp );
                    put( "datetime", Coincatch.this.iso8601(timestamp) );
                }});
            }
            Object sorted = this.sortBy(rates, "timestamp");
            return this.filterBySinceLimit(sorted, since, limit);
        }, io.github.ccxt.Exchange.VIRTUAL_EXECUTOR);

    }

