    public Object parseBalance(Object balances)
    {
        //
        // spot
        //     [
        //         {
        //             "coinId": 2,
        //             "coinName": "USDT",
        //             "available": "99.20000000",
        //             "frozen": "0.00000000",
        //             "lock": "0.00000000",
        //             "uTime": "1724938746000"
        //         }
        //     ]
        //
        // swap
        //     [
        //         {
        //             "marginCoin": "USDT",
        //             "locked": "0",
        //             "available": "60",
        //             "crossMaxAvailable": "60",
        //             "fixedMaxAvailable": "60",
        //             "maxTransferOut": "60",
        //             "equity": "60",
        //             "usdtEquity": "60",
        //             "btcEquity": "0.001002360626",
        //             "crossRiskRate": "0",
        //             "unrealizedPL": "0",
        //             "bonus": "0",
        //             "crossedUnrealizedPL": null,
        //             "isolatedUnrealizedPL": null
        //         }
        //     ]
        //
        Object result = new java.util.HashMap<String, Object>() {{
            put( "info", balances );
        }};
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(balances)); i++)
        {
            Object balanceEntry = this.safeDict(balances, i, new java.util.HashMap<String, Object>() {{}});
            Object currencyId = this.safeString2(balanceEntry, "coinName", "marginCoin");
            Object code = this.safeCurrencyCode(currencyId);
            Object account = this.account();
            Helpers.addElementToObject(account, "free", this.safeString(balanceEntry, "available"));
            Object locked = this.safeString2(balanceEntry, "lock", "locked");
            Object frozen = this.safeString(balanceEntry, "frozen", "0");
            Helpers.addElementToObject(account, "used", Precise.stringAdd(locked, frozen));
            Helpers.addElementToObject(account, "total", this.safeString(balanceEntry, "equity"));
            Helpers.addElementToObject(result, code, account);
        }
        return this.safeBalance(result);
    }

