    public Object parseTransaction(Object transaction, Object... optionalArgs)
    {
        //
        // fetchDeposits
        //
        //     {
        //         "id": "1213046466852196352",
        //         "txId": "824246b030cd84d56400661303547f43a1d9fef66cf968628dd5112f362053ff",
        //         "coin": "USDT",
        //         "type": "deposit",
        //         "amount": "99.20000000",
        //         "status": "success",
        //         "toAddress": "TKTUt7qiTaMgnTwZXjE3ZBkPB6LKhLPJyZ",
        //         "fee": null,
        //         "chain": "TRX(TRC20)",
        //         "confirm": null,
        //         "clientOid": null,
        //         "tag": null,
        //         "fromAddress": null,
        //         "dest": "on_chain",
        //         "cTime": "1724938735688",
        //         "uTime": "1724938746015"
        //     }
        //
        // withdraw
        //
        //     {
        //         "code": "00000",
        //         "msg": "success",
        //         "data": {
        //             "orderId":888291686266343424",
        //             "clientOrderId":"123"
        //         }
        //     }
        //
        Object currency = Helpers.getArg(optionalArgs, 0, null);
        Object status = this.safeString(transaction, "status");
        if (Helpers.isTrue(Helpers.isEqual(status, "success")))
        {
            status = "ok";
        }
        Object txid = this.safeString(transaction, "txId");
        Object coin = this.safeString(transaction, "coin");
        Object code = this.safeCurrencyCode(coin, currency);
        Object timestamp = this.safeInteger(transaction, "cTime");
        Object amount = this.safeNumber(transaction, "amount");
        Object networkId = this.safeString(transaction, "chain");
        Object network = this.safeString(Helpers.GetValue(this.options, "networksById"), networkId, networkId);
        Object addressTo = this.safeString(transaction, "toAddress");
        Object addressFrom = this.safeString(transaction, "fromAddress");
        Object tag = this.safeString(transaction, "tag");
        Object type = this.safeString(transaction, "type");
        Object feeCost = this.safeNumber(transaction, "fee");
        Object fee = null;
        if (Helpers.isTrue(!Helpers.isEqual(feeCost, null)))
        {
            final Object finalFeeCost = feeCost;
            fee = new java.util.HashMap<String, Object>() {{
                put( "cost", finalFeeCost );
                put( "currency", code );
            }};
        }
        final Object finalStatus = status;
        final Object finalFee = fee;
        return new java.util.HashMap<String, Object>() {{
            put( "info", transaction );
            put( "id", Coincatch.this.safeString2(transaction, "id", "orderId") );
            put( "txid", txid );
            put( "timestamp", timestamp );
            put( "datetime", Coincatch.this.iso8601(timestamp) );
            put( "network", network );
            put( "address", null );
            put( "addressTo", addressTo );
            put( "addressFrom", addressFrom );
            put( "tag", tag );
            put( "tagTo", null );
            put( "tagFrom", null );
            put( "type", type );
            put( "amount", amount );
            put( "currency", code );
            put( "status", finalStatus );
            put( "updated", null );
            put( "internal", null );
            put( "comment", null );
            put( "fee", finalFee );
        }};
    }

