    public Object createSwapOrderRequest(Object symbol, Object type, Object side, Object amount, Object... optionalArgs)
    {
        /**
        * @method
        * @ignore
        * @name coincatch#createSwapOrderRequest
        * @description helper function to build request
        * @param {string} symbol unified symbol of the market to create an order in
        * @param {string} type 'market' or 'limit'
        * @param {string} side 'buy' or 'sell'
        * @param {float} amount how much of you want to trade in units of the base currency
        * @param {float} [price] the price that the order is to be fulfilled, in units of the quote currency, ignored in market orders
        * @param {object} [params] extra parameters specific to the exchange API endpoint
        * @param {bool} [params.hedged] must be set to true if position mode is hedged (default false)
        * @param {bool} [params.postOnly] *non-trigger orders only* if true, the order will only be posted to the order book and not executed immediately
        * @param {bool} [params.reduceOnly] true or false whether the order is reduce only
        * @param {string} [params.timeInForce] *non-trigger orders only* 'GTC', 'FOK', 'IOC' or 'PO'
        * @param {string} [params.clientOrderId] a unique id for the order
        * @param {float} [params.triggerPrice] the price that the order is to be triggered at
        * @param {float} [params.stopLossPrice] The price at which a stop loss order is triggered at
        * @param {float} [params.takeProfitPrice] The price at which a take profit order is triggered at
        * @param {object} [params.takeProfit] *takeProfit object in params* containing the triggerPrice at which the attached take profit order will be triggered (perpetual swap markets only)
        * @param {float} [params.takeProfit.triggerPrice] take profit trigger price
        * @param {object} [params.stopLoss] *stopLoss object in params* containing the triggerPrice at which the attached stop loss order will be triggered (perpetual swap markets only)
        * @param {float} [params.stopLoss.triggerPrice] stop loss trigger price
        * @returns {object} request to be sent to the exchange
        */
        Object price = Helpers.getArg(optionalArgs, 0, null);
        Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
        Object methodName = "createSwapOrderRequest";
        var methodNameparametersVariable = this.handleParamString(parameters, "methodName", methodName);
        methodName = ((java.util.List<Object>) methodNameparametersVariable).get(0);
        parameters = ((java.util.List<Object>) methodNameparametersVariable).get(1);
        Object market = this.market(symbol);
        Object request = new java.util.HashMap<String, Object>() {{
            put( "symbol", Helpers.GetValue(market, "id") );
            put( "marginCoin", Helpers.GetValue(market, "settleId") );
            put( "size", Coincatch.this.amountToPrecision(symbol, amount) );
        }};
        var requestparametersVariable = this.handleOptionParamsAndRequest(parameters, methodName, "clientOrderId", request, "clientOid");
        request = ((java.util.List<Object>) requestparametersVariable).get(0);
        parameters = ((java.util.List<Object>) requestparametersVariable).get(1);
        Object isMarketOrder = (Helpers.isEqual(type, "market"));
        parameters = this.handleTriggerStopLossAndTakeProfit(symbol, side, type, price, methodName, parameters);
        Object endpointType = this.safeString(parameters, "endpointType");
        if (Helpers.isTrue(Helpers.isTrue((Helpers.isEqual(endpointType, null))) || Helpers.isTrue((Helpers.isEqual(endpointType, "standard")))))
        {
            Object timeInForceAndParams = this.handleTimeInForceAndPostOnly(methodName, parameters, isMarketOrder); // only for non-trigger orders
            parameters = Helpers.GetValue(timeInForceAndParams, "params");
            Object timeInForce = Helpers.GetValue(timeInForceAndParams, "timeInForce");
            if (Helpers.isTrue(!Helpers.isEqual(timeInForce, null)))
            {
                Helpers.addElementToObject(request, "timeInForceValue", timeInForce);
            }
            if (Helpers.isTrue(!Helpers.isEqual(price, null)))
            {
                Helpers.addElementToObject(request, "price", this.priceToPrecision(symbol, price));
            }
        }
        if (Helpers.isTrue((!Helpers.isEqual(endpointType, "tpsl"))))
        {
            Helpers.addElementToObject(request, "orderType", type);
            Object sideIsExchangeSpecific = false;
            Object hedged = false;
            if (Helpers.isTrue(Helpers.isTrue(Helpers.isTrue(Helpers.isTrue(Helpers.isTrue(Helpers.isTrue((Helpers.isEqual(side, "buy_single"))) || Helpers.isTrue((Helpers.isEqual(side, "sell_single")))) || Helpers.isTrue((Helpers.isEqual(side, "open_long")))) || Helpers.isTrue((Helpers.isEqual(side, "open_short")))) || Helpers.isTrue((Helpers.isEqual(side, "close_long")))) || Helpers.isTrue((Helpers.isEqual(side, "close_short")))))
            {
                sideIsExchangeSpecific = true;
                if (Helpers.isTrue(Helpers.isTrue((!Helpers.isEqual(side, "buy_single"))) && Helpers.isTrue((!Helpers.isEqual(side, "sell_single")))))
                {
                    hedged = true;
                }
            }
            if (!Helpers.isTrue(sideIsExchangeSpecific))
            {
                var hedgedparametersVariable = this.handleOptionAndParams(parameters, methodName, "hedged", hedged);
                hedged = ((java.util.List<Object>) hedgedparametersVariable).get(0);
                parameters = ((java.util.List<Object>) hedgedparametersVariable).get(1);
                // hedged and non-hedged orders have different side values and reduceOnly handling
                Object reduceOnly = this.safeBool(parameters, "reduceOnly");
                if (Helpers.isTrue(hedged))
                {
                    if (Helpers.isTrue(Helpers.isTrue((!Helpers.isEqual(reduceOnly, null))) && Helpers.isTrue(reduceOnly)))
                    {
                        if (Helpers.isTrue(Helpers.isEqual(side, "buy")))
                        {
                            side = "close_short";
                        } else if (Helpers.isTrue(Helpers.isEqual(side, "sell")))
                        {
                            side = "close_long";
                        }
                    } else
                    {
                        if (Helpers.isTrue(Helpers.isEqual(side, "buy")))
                        {
                            side = "open_long";
                        } else if (Helpers.isTrue(Helpers.isEqual(side, "sell")))
                        {
                            side = "open_short";
                        }
                    }
                } else
                {
                    side = Helpers.add(((String)side).toLowerCase(), "_single");
                }
            }
            if (Helpers.isTrue(hedged))
            {
                parameters = this.omit(parameters, "reduceOnly");
            }
            Helpers.addElementToObject(request, "side", side);
        }
        return this.extend(request, parameters);
    }

    public Object handleTriggerStopLossAndTakeProfit(Object symbol, Object side, Object type, Object price, Object... optionalArgs)
    {
        Object methodName = Helpers.getArg(optionalArgs, 0, "createOrder");
        Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
        Object request = new java.util.HashMap<String, Object>() {{}};
        Object endpointType = "standard"; // standard, trigger, tpsl, trailing - to define the endpoint to use
        Object stopLossPrice = this.safeString(parameters, "stopLossPrice");
        Object takeProfitPrice = this.safeString(parameters, "takeProfitPrice");
        Object requestTriggerPrice = null;
        Object takeProfit = this.safeDict(parameters, "takeProfit");
        Object stopLoss = this.safeDict(parameters, "stopLoss");
        Object triggerPrice = this.safeString2(parameters, "triggerPrice", "stopPrice");
        Object isTrigger = (!Helpers.isEqual(triggerPrice, null));
        Object trailingPercent = this.safeString(parameters, "trailingPercent");
        Object trailingTriggerPrice = this.safeString(parameters, "trailingTriggerPrice");
        Object hasTPPrice = (!Helpers.isEqual(takeProfitPrice, null));
        Object hasSLPrice = (!Helpers.isEqual(stopLossPrice, null));
        Object hasTakeProfit = (!Helpers.isEqual(takeProfit, null));
        if (Helpers.isTrue(Helpers.isTrue(hasTakeProfit) && !Helpers.isTrue(hasTPPrice)))
        {
            takeProfitPrice = this.safeString(takeProfit, "triggerPrice");
            hasTPPrice = (!Helpers.isEqual(takeProfitPrice, null));
        }
        Object hasStopLoss = (!Helpers.isEqual(stopLoss, null));
        if (Helpers.isTrue(Helpers.isTrue(hasStopLoss) && !Helpers.isTrue(hasSLPrice)))
        {
            stopLossPrice = this.safeString(stopLoss, "triggerPrice");
            hasSLPrice = (!Helpers.isEqual(stopLossPrice, null));
        }
        Object hasBothTPAndSL = Helpers.isTrue(hasTPPrice) && Helpers.isTrue(hasSLPrice);
        Object isTrailingPercentOrder = (!Helpers.isEqual(trailingPercent, null));
        Object isMarketOrder = (Helpers.isEqual(type, "market"));
        // handle with triggerPrice stopLossPrice and takeProfitPrice
        if (Helpers.isTrue(Helpers.isTrue(Helpers.isTrue(hasBothTPAndSL) || Helpers.isTrue(isTrigger)) || Helpers.isTrue((Helpers.isEqual(methodName, "createOrderWithTakeProfitAndStopLoss")))))
        {
            if (Helpers.isTrue(isTrigger))
            {
                if (Helpers.isTrue(isMarketOrder))
                {
                    Helpers.addElementToObject(request, "triggerType", "market_price");
                } else
                {
                    Helpers.addElementToObject(request, "triggerType", "fill_price");
                    Helpers.addElementToObject(request, "executePrice", this.priceToPrecision(symbol, price));
                }
                Helpers.addElementToObject(request, "triggerPrice", this.priceToPrecision(symbol, triggerPrice));
                endpointType = "trigger"; // if order also has triggerPrice we use endpoint for trigger orders
            }
            if (Helpers.isTrue(Helpers.isEqual(methodName, "createOrders")))
            {
                endpointType = null; // we do not provide endpointType for createOrders
            }
            if (Helpers.isTrue(hasTPPrice))
            {
                Helpers.addElementToObject(request, "presetTakeProfitPrice", takeProfitPrice);
            }
            if (Helpers.isTrue(hasSLPrice))
            {
                Helpers.addElementToObject(request, "presetStopLossPrice", stopLossPrice);
            }
        } else if (Helpers.isTrue(Helpers.isTrue(Helpers.isTrue(hasTPPrice) || Helpers.isTrue(hasSLPrice)) || Helpers.isTrue(isTrailingPercentOrder)))
        {
            if (!Helpers.isTrue(isMarketOrder))
            {
                throw new NotSupported((String)Helpers.add(Helpers.add(Helpers.add(Helpers.add(Helpers.add(this.id, " "), methodName), "() supports does not support "), type), " type of stop loss and take profit orders (only market type is supported for stop loss and take profit orders). To create a market order with stop loss or take profit attached use createOrderWithTakeProfitAndStopLoss()")) ;
            }
            endpointType = "tpsl"; // if order has only one of the two we use endpoint for tpsl orders
            Object holdSide = "long";
            if (Helpers.isTrue(Helpers.isEqual(side, "buy")))
            {
                holdSide = "short";
            }
            Helpers.addElementToObject(request, "holdSide", holdSide);
            if (Helpers.isTrue(isTrailingPercentOrder))
            {
                if (Helpers.isTrue(Helpers.isEqual(trailingTriggerPrice, null)))
                {
                    throw new ArgumentsRequired((String)Helpers.add(Helpers.add(Helpers.add(this.id, " "), methodName), "() requires the trailingTriggerPrice parameter for trailing stop orders")) ;
                }
                requestTriggerPrice = trailingTriggerPrice;
                Helpers.addElementToObject(request, "rangeRate", trailingPercent);
                Helpers.addElementToObject(request, "planType", "moving_plan");
            } else if (Helpers.isTrue(hasTPPrice))
            {
                requestTriggerPrice = takeProfitPrice;
                Helpers.addElementToObject(request, "planType", "profit_plan");
            } else
            {
                requestTriggerPrice = stopLossPrice;
                Helpers.addElementToObject(request, "planType", "loss_plan");
            }
            Helpers.addElementToObject(request, "triggerPrice", this.priceToPrecision(symbol, requestTriggerPrice));
        }
        if (Helpers.isTrue(!Helpers.isEqual(endpointType, null)))
        {
            Helpers.addElementToObject(request, "endpointType", endpointType);
        }
        parameters = this.omit(parameters, new java.util.ArrayList<Object>(java.util.Arrays.asList("stopLoss", "takeProfit", "stopLossPrice", "takeProfitPrice", "triggerPrice", "stopPrice", "trailingPercent", "trailingTriggerPrice")));
        return this.extend(request, parameters);
    }

