    public Object parseFeeDetailString(Object feeDetailString)
    {
        Object result = new java.util.ArrayList<Object>(java.util.Arrays.asList());
        Object feeDetail = this.parseJson(feeDetailString);
        if (Helpers.isTrue(feeDetail))
        {
            Object keys = new java.util.ArrayList<Object>(((java.util.Map<String, Object>)feeDetail).keySet());
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(keys)); i++)
            {
                Object currencyId = this.safeString(keys, i);
                if (Helpers.isTrue(Helpers.inOp(this.currencies_by_id, currencyId)))
                {
                    Object currency = this.safeCurrencyCode(currencyId);
                    Object feeEntry = this.safeDict(feeDetail, currencyId, new java.util.HashMap<String, Object>() {{}});
                    Object amount = Precise.stringAbs(this.safeString(feeEntry, "totalFee"));
                    ((java.util.List<Object>)result).add(new java.util.HashMap<String, Object>() {{
                        put( "currency", currency );
                        put( "amount", amount );
                    }});
                }
            }
        }
        return result;
    }

