    public Object parseLeverage(Object leverage, Object... optionalArgs)
    {
        //
        // fetchLeverage
        //     {
        //         "marginCoin": "ETH",
        //         "locked": "0",
        //         "available": "0.01",
        //         "crossMaxAvailable": "0.01",
        //         "fixedMaxAvailable": "0.01",
        //         "maxTransferOut": "0.01",
        //         "equity": "0.01",
        //         "usdtEquity": "22.97657025",
        //         "btcEquity": "0.000386195288",
        //         "crossRiskRate": "0",
        //         "crossMarginLeverage": 100,
        //         "fixedLongLeverage": 100,
        //         "fixedShortLeverage": 100,
        //         "marginMode": "crossed",
        //         "holdMode": "double_hold",
        //         "unrealizedPL": "0",
        //         "bonus": "0",
        //         "crossedUnrealizedPL": "0",
        //         "isolatedUnrealizedPL": ""
        //     }
        //
        // setLeverage
        //     {
        //         "symbol": "ETHUSD_DMCBL",
        //         "marginCoin": "ETH",
        //         "longLeverage": 2,
        //         "shortLeverage": 2,
        //         "crossMarginLeverage": 2,
        //         "marginMode": "crossed"
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object marketId = this.safeString(leverage, "symbol");
        market = this.safeMarketCustom(marketId, market);
        Object marginMode = this.parseMarginModeType(this.safeStringLower(leverage, "marginMode"));
        Object longLeverage = this.safeInteger2(leverage, "fixedLongLeverage", "longLeverage");
        Object shortLeverage = this.safeInteger2(leverage, "fixedShortLeverage", "shortLeverage");
        Object crossMarginLeverage = this.safeInteger(leverage, "crossMarginLeverage");
        if (Helpers.isTrue(Helpers.isEqual(marginMode, "cross")))
        {
            longLeverage = crossMarginLeverage;
            shortLeverage = crossMarginLeverage;
        }
        final Object finalMarket = market;
        final Object finalMarginMode = marginMode;
        final Object finalLongLeverage = longLeverage;
        final Object finalShortLeverage = shortLeverage;
        return new java.util.HashMap<String, Object>() {{
            put( "info", leverage );
            put( "symbol", Helpers.GetValue(finalMarket, "symbol") );
            put( "marginMode", finalMarginMode );
            put( "longLeverage", finalLongLeverage );
            put( "shortLeverage", finalShortLeverage );
        }};
    }

    public java.util.concurrent.CompletableFuture<Object> modifyMarginHelper(Object symbol, Object amount2, Object type2, Object... optionalArgs)
    {
        final Object amount3 = amount2;
        final Object type3 = type2;
        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {
            Object amount = amount3;
            Object type = type3;
            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            Object methodName = "modifyMarginHelper";
            var methodNameparametersVariable = this.handleParamString(parameters, "methodName", methodName);
            methodName = ((java.util.List<Object>) methodNameparametersVariable).get(0);
            parameters = ((java.util.List<Object>) methodNameparametersVariable).get(1);
            (this.loadMarkets()).join();
            Object market = this.market(symbol);
            if (Helpers.isTrue(!Helpers.isEqual(Helpers.GetValue(market, "type"), "swap")))
            {
                throw new NotSupported((String)Helpers.add(Helpers.add(Helpers.add(Helpers.add(Helpers.add(this.id, " "), methodName), "() is not supported for "), Helpers.GetValue(market, "type")), " type of markets")) ;
            }
            amount = this.amountToPrecision(symbol, amount);
            final Object finalAmount = amount;
            Object request = new java.util.HashMap<String, Object>() {{
                put( "symbol", Helpers.GetValue(market, "id") );
                put( "marginCoin", Helpers.GetValue(market, "settleId") );
                put( "amount", finalAmount );
            }};
            Object side = null;
            var sideparametersVariable = this.handleOptionAndParams(parameters, methodName, "side");
            side = ((java.util.List<Object>) sideparametersVariable).get(0);
            parameters = ((java.util.List<Object>) sideparametersVariable).get(1);
            if (Helpers.isTrue(!Helpers.isEqual(side, null)))
            {
                Helpers.addElementToObject(request, "holdSide", side);
            }
            Object response = (this.privatePostApiMixV1AccountSetMargin(this.extend(request, parameters))).join();
            // todo check response
            // always returns error
            // addMargin - "code":"45006","msg":"Insufficient position","requestTime":1729162281543,"data":null
            // reduceMargin - "code":"40800","msg":"Insufficient amount of margin","requestTime":1729162362718,"data":null
            if (Helpers.isTrue(Helpers.isEqual(type, "reduce")))
            {
                amount = Precise.stringAbs(amount);
            }
            Object parsedAmount = this.parseNumber(amount);
            final Object finalType = type;
            return this.extend(this.parseMarginModification(response, market), new java.util.HashMap<String, Object>() {{
                put( "amount", parsedAmount );
                put( "type", finalType );
            }});
        }, io.github.ccxt.Exchange.VIRTUAL_EXECUTOR);

    }

