    public Object parsePosition(Object position, Object... optionalArgs)
    {
        //
        //     {
        //         "marginCoin": "USDT",
        //         "symbol": "ETHUSDT_UMCBL",
        //         "holdSide": "long",
        //         "openDelegateCount": "0",
        //         "margin": "2.55512",
        //         "available": "0.01",
        //         "locked": "0",
        //         "total": "0.01",
        //         "leverage": 10,
        //         "achievedProfits": "0",
        //         "averageOpenPrice": "2555.12",
        //         "marginMode": "crossed",
        //         "holdMode": "double_hold",
        //         "unrealizedPL": "0.0093",
        //         "liquidationPrice": "-3433.378333",
        //         "keepMarginRate": "0.0033",
        //         "marketPrice": "2556.05",
        //         "marginRatio": "0.001661599511",
        //         "autoMargin": "off",
        //         "cTime": "1726919819686",
        //         "uTime": "1726919819686"
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object marketId = this.safeString(position, "symbol");
        Object settleId = this.safeString(position, "marginCoin");
        market = this.safeMarketCustom(marketId, market, settleId);
        Object timestamp = this.safeInteger(position, "cTime");
        Object marginMode = this.safeString(position, "marginMode");
        Object isHedged = null;
        Object holdMode = this.safeString(position, "holdMode");
        if (Helpers.isTrue(Helpers.isEqual(holdMode, "double_hold")))
        {
            isHedged = true;
        } else if (Helpers.isTrue(Helpers.isEqual(holdMode, "single_hold")))
        {
            isHedged = false;
        }
        Object margin = this.safeNumber(position, "margin");
        Object keepMarginRate = this.safeString(position, "keepMarginRate");
        final Object finalMarket = market;
        final Object finalIsHedged = isHedged;
        return this.safePosition(new java.util.HashMap<String, Object>() {{
            put( "symbol", Helpers.GetValue(finalMarket, "symbol") );
            put( "id", null );
            put( "timestamp", timestamp );
            put( "datetime", Coincatch.this.iso8601(timestamp) );
            put( "contracts", Coincatch.this.safeNumber(position, "total") );
            put( "contractSize", null );
            put( "side", Coincatch.this.safeStringLower(position, "holdSide") );
            put( "notional", margin );
            put( "leverage", Coincatch.this.safeInteger(position, "leverage") );
            put( "unrealizedPnl", Coincatch.this.safeNumber(position, "unrealizedPL") );
            put( "realizedPnl", Coincatch.this.safeNumber(position, "achievedProfits") );
            put( "collateral", null );
            put( "entryPrice", Coincatch.this.safeNumber(position, "averageOpenPrice") );
            put( "markPrice", Coincatch.this.safeNumber(position, "marketPrice") );
            put( "liquidationPrice", Coincatch.this.safeNumber(position, "liquidationPrice") );
            put( "marginMode", Coincatch.this.parseMarginModeType(marginMode) );
            put( "hedged", finalIsHedged );
            put( "maintenanceMargin", null );
            put( "maintenanceMarginPercentage", Coincatch.this.parseNumber(Precise.stringMul(keepMarginRate, "100")) );
            put( "initialMargin", margin );
            put( "initialMarginPercentage", null );
            put( "marginRatio", Coincatch.this.safeNumber(position, "marginRatio") );
            put( "lastUpdateTimestamp", Coincatch.this.safeInteger(position, "uTime") );
            put( "lastPrice", null );
            put( "stopLossPrice", null );
            put( "takeProfitPrice", null );
            put( "percentage", null );
            put( "info", position );
        }});
    }

    public Object safeMarketCustom(Object marketId, Object... optionalArgs)
    {
        // dmcbl markets have the same id and market type but different settleId
        // so we need to resolve the market by settleId
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object settleId = Helpers.getArg(optionalArgs, 1, null);
        try
        {
            market = this.safeMarket(marketId, market);
        } catch(Exception e)
        {
            Object marketsWithCurrentId = this.safeList(this.markets_by_id, marketId, new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            if (Helpers.isTrue(Helpers.isEqual(settleId, null)))
            {
                market = Helpers.GetValue(marketsWithCurrentId, 0); // if settleId is not provided, return the first market with the current id
            } else
            {
                for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(marketsWithCurrentId)); i++)
                {
                    Object marketWithCurrentId = Helpers.GetValue(marketsWithCurrentId, i);
                    if (Helpers.isTrue(Helpers.isEqual(Helpers.GetValue(marketWithCurrentId, "settleId"), settleId)))
                    {
                        market = marketWithCurrentId;
                        break;
                    }
                }
            }
        }
        return market;
    }

