    public Object parseLedgerEntry(Object item, Object... optionalArgs)
    {
        //
        // spot
        //     {
        //         "billId": "1220289012519190529",
        //         "coinId": 2,
        //         "coinName": "USDT",
        //         "groupType": "transfer",
        //         "bizType": "Transfer out",
        //         "quantity": "-40.00000000",
        //         "balance": "4.43878673",
        //         "fees": "0.00000000",
        //         "cTime": "1726665493092"
        //     }
        //
        // swap
        //     {
        //         "id": "1220288640761122816",
        //         "symbol": null,
        //         "marginCoin": "ETH",
        //         "amount": "0.01",
        //         "fee": "0",
        //         "feeByCoupon": "",
        //         "feeCoin": "ETH",
        //         "business": "trans_from_exchange",
        //         "cTime": "1726665404563"
        //     }
        //
        Object currency = Helpers.getArg(optionalArgs, 0, null);
        Object timestamp = this.safeInteger(item, "cTime");
        Object settleId = this.safeString2(item, "coinName", "marginCoin");
        Object market = null;
        Object marketId = this.safeString(item, "symbol");
        market = this.safeMarketCustom(marketId, market, settleId);
        Object amountString = this.safeString2(item, "quantity", "amount");
        Object direction = "in";
        if (Helpers.isTrue(Precise.stringLt(amountString, "0")))
        {
            direction = "out";
            amountString = Precise.stringMul(amountString, "-1");
        }
        Object fee = new java.util.HashMap<String, Object>() {{
            put( "cost", Precise.stringAbs(Coincatch.this.safeString2(item, "fee", "fees")) );
            put( "currency", Coincatch.this.safeString(item, "feeCoin") );
        }};
        final Object finalDirection = direction;
        final Object finalMarket = market;
        final Object finalAmountString = amountString;
        return this.safeLedgerEntry(new java.util.HashMap<String, Object>() {{
            put( "id", Coincatch.this.safeString2(item, "billId", "id") );
            put( "info", item );
            put( "timestamp", timestamp );
            put( "datetime", Coincatch.this.iso8601(timestamp) );
            put( "account", null );
            put( "direction", finalDirection );
            put( "referenceId", null );
            put( "referenceAccount", null );
            put( "type", Coincatch.this.parseLedgerEntryType(Coincatch.this.safeStringLower2(item, "bizType", "business")) );
            put( "currency", Coincatch.this.safeCurrencyCode(settleId, currency) );
            put( "symbol", Helpers.GetValue(finalMarket, "symbol") );
            put( "amount", finalAmountString );
            put( "before", null );
            put( "after", Coincatch.this.safeString(item, "balance") );
            put( "status", "ok" );
            put( "fee", fee );
        }}, currency);
    }

    public Object parseLedgerEntryType(Object type)
    {
        Object types = new java.util.HashMap<String, Object>() {{
            put( "deposit", "deposit" );
            put( "withdraw", "withdrawal" );
            put( "buy", "trade" );
            put( "sell", "trade" );
            put( "deduction of handling fee", "fee" );
            put( "transfer-in", "transfer" );
            put( "transfer in", "transfer" );
            put( "transfer out", "transfer" );
            put( "rebate rewards", "rebate" );
            put( "airdrop rewards", "rebate" );
            put( "usdt contract rewards", "rebate" );
            put( "mix contract rewards", "rebate" );
            put( "system lock", "system lock" );
            put( "user lock", "user lock" );
            put( "open_long", "trade" );
            put( "open_short", "trade" );
            put( "close_long", "trade" );
            put( "close_short", "trade" );
            put( "trans_from_exchange", "transfer" );
            put( "trans_to_exchange", "transfer" );
            put( "contract_settle_fee", "fee" );
            put( "burst_long_loss_query", "trade" );
            put( "burst_short_loss_query", "trade" );
        }};
        return this.safeString(types, type, type);
    }

    public Object handleErrors(Object code, Object reason, Object url, Object method, Object headers, Object body, Object response, Object requestHeaders, Object requestBody)
    {
        if (!Helpers.isTrue(response))
        {
            return null;  // fallback to default error handler
        }
        Object message = this.safeString(response, "msg");
        Object feedback = Helpers.add(Helpers.add(this.id, " "), body);
        Object messageCode = this.safeString(response, "code");
        Object success = Helpers.isTrue((Helpers.isEqual(message, "success"))) || Helpers.isTrue((Helpers.isEqual(message, null)));
        if (Helpers.isTrue(Helpers.isGreaterThanOrEqual(Helpers.getIndexOf(url, "batch"), 0)))
        {
            Object data = this.safeDict(response, "data", new java.util.HashMap<String, Object>() {{}});
            Object failure = this.safeList2(data, "failure", "fail_infos", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            if (!Helpers.isTrue(this.isEmpty(failure)))
            {
                success = false;
                Object firstEntry = this.safeDict(failure, 0, new java.util.HashMap<String, Object>() {{}});
                messageCode = this.safeString(firstEntry, "errorCode");
                message = this.safeString(firstEntry, "errorMsg");
            }
        }
        if (!Helpers.isTrue(success))
        {
            this.throwExactlyMatchedException(Helpers.GetValue(this.exceptions, "exact"), messageCode, feedback);
            this.throwBroadlyMatchedException(Helpers.GetValue(this.exceptions, "broad"), message, feedback);
            throw new ExchangeError((String)feedback) ;
        }
        return null;
    }

    public Object sign(Object path, Object... optionalArgs)
    {
        Object api = Helpers.getArg(optionalArgs, 0, "public");
        Object method = Helpers.getArg(optionalArgs, 1, "GET");
        Object parameters = Helpers.getArg(optionalArgs, 2, new java.util.HashMap<String, Object>() {{}});
        Object headers = Helpers.getArg(optionalArgs, 3, null);
        Object body = Helpers.getArg(optionalArgs, 4, null);
        Object endpoint = Helpers.add("/", path);
        if (Helpers.isTrue(Helpers.isEqual(method, "GET")))
        {
            Object query = this.urlencode(parameters);
            if (Helpers.isTrue(!Helpers.isEqual(Helpers.getArrayLength(query), 0)))
            {
                endpoint = Helpers.add(endpoint, Helpers.add("?", query));
            }
        }
        if (Helpers.isTrue(Helpers.isEqual(api, "private")))
        {
            this.checkRequiredCredentials();
            Object timestamp = this.numberToString(this.milliseconds());
            Object suffix = "";
            if (Helpers.isTrue(!Helpers.isEqual(method, "GET")))
            {
                body = this.json(parameters);
                suffix = body;
            }
            Object payload = Helpers.add(Helpers.add(Helpers.add(timestamp, method), endpoint), suffix);
            Object signature = this.hmac(this.encode(payload), this.encode(this.secret), sha256(), "base64");
            final Object finalTimestamp = timestamp;
            headers = new java.util.HashMap<String, Object>() {{
                put( "ACCESS-KEY", Coincatch.this.apiKey );
                put( "ACCESS-SIGN", signature );
                put( "ACCESS-TIMESTAMP", finalTimestamp );
                put( "ACCESS-PASSPHRASE", Coincatch.this.password );
                put( "Content-Type", "application/json" );
                put( "X-CHANNEL-API-CODE", Coincatch.this.safeString(Coincatch.this.options, "brokerId", "47cfy") );
            }};
        }
        Object url = Helpers.add(Helpers.GetValue(Helpers.GetValue(this.urls, "api"), api), endpoint);
        final Object finalMethod = method;
        final Object finalBody = body;
        final Object finalHeaders = headers;
        return new java.util.HashMap<String, Object>() {{
            put( "url", url );
            put( "method", finalMethod );
            put( "body", finalBody );
            put( "headers", finalHeaders );
        }};
    }
